import urllib.parse

from flask import redirect, url_for, request, session


def login_redirect(endpoint='index', **values):
    """
    Redirects the user to their intended destination after successful login.

    If a 'next' URL is present in the request arguments or session, it will
    redirect there. Otherwise, it redirects to the specified endpoint.

    The 'next' URL is stored in the session if the current request is a GET
    request and the user is not authenticated, allowing the login page
    to redirect back to the original page after successful login.

    Args:
        endpoint (str): The name of the endpoint to redirect to if no 'next'
                        URL is found. Defaults to 'index'.
        **values: Keyword arguments to pass to url_for when generating
                  the default redirect URL.

    Returns:
        flask.Response: A redirect response.
    """
    if request.method == 'GET' and 'user_id' not in session:  # Assuming 'user_id' indicates authentication
        # Store the current URL as 'next' if not already a login page
        if request.endpoint != 'login':  # Assuming 'login' is your login endpoint name
            session['next_url'] = request.url
        else:
            # If already on login page, clear any previous 'next_url'
            session.pop('next_url', None)

    next_url = request.args.get('next') or session.pop('next_url', None)

    if next_url:
        # Validate the next_url to prevent open redirects
        # Ensure it's a relative path or points to the same host
        parsed_url = urllib.parse.urlparse(next_url)
        if not parsed_url.netloc or parsed_url.netloc == request.host:
            return redirect(next_url)

    return redirect(url_for(endpoint, **values))